const config = $input.first().json;
const rssRaw = (config.COMPETITOR_RSS_FEEDS || '').toString().trim();
const redditRaw = (config.REDDIT_SUBREDDITS || '').toString().trim();
const rssUrls = rssRaw ? rssRaw.split(',').map(s => s.trim()).filter(Boolean) : [];
const subreddits = redditRaw ? redditRaw.split(',').map(s => s.trim()).filter(Boolean) : [];
const normalized = subreddits.map(s => /^r\//.test(s) ? s : 'r/' + s);
if (rssUrls.length === 0 && normalized.length === 0) {
  return [{ json: { no_sources: true } }];
}
const out = [];
rssUrls.forEach(url => out.push({ json: { type: 'rss', url } }));
normalized.forEach(sub => out.push({ json: { type: 'reddit', subreddit: sub } }));
return out;

const all = $input.all();
const out = [];
for (let i = 0; i < all.length; i++) {
  const xml = all[i].json.body || all[i].json;
  const feedUrl = typeof $('🔀 Route by Type').item(i).json !== 'undefined' ? $('🔀 Route by Type').item(i).json.url : '';
  const source = feedUrl || 'rss';
  const itemMatches = String(xml).match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];
  itemMatches.slice(0, 10).forEach((item) => {
    const title = (item.match(/<title[^>]*><!\[CDATA\[([^\]]+)\]\]><\/title>/) || item.match(/<title[^>]*>([^<]+)<\/title>/))?.[1] || '';
    const link = (item.match(/<link[^>]*>([^<]+)<\/link>/))?.[1] || '';
    const pubDate = (item.match(/<pubDate[^>]*>([^<]+)<\/pubDate>/))?.[1] || '';
    const description = (item.match(/<description[^>]*><!\[CDATA\[([^\]]+)\]\]><\/description>/) || item.match(/<description[^>]*>([^<]+)<\/description>/))?.[1] || '';
    out.push({ json: { source, title: title.trim(), url: link.trim(), published: pubDate, detected_at: new Date().toISOString() } });
  });
}
return out.length ? out : [{ json: { source: 'rss', title: '', url: '', published: '', detected_at: new Date().toISOString() } }];

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const data = items[i].json?.data?.children || [];
  const subreddit = $('🔀 Route by Type').item(i).json?.subreddit || 'reddit';
  data.filter(post => post.data && post.data.ups >= 100).forEach(post => {
    out.push({ json: { source: 'reddit', title: post.data.title, url: 'https://reddit.com' + post.data.permalink, published: new Date(post.data.created_utc * 1000).toISOString(), detected_at: new Date().toISOString() } });
  });
}
return out.length ? out : [{ json: { source: 'reddit', title: '', url: '', published: '', detected_at: new Date().toISOString() } }];

// Parse Google Trends (API returns )]}' prefix)
const raw = String($input.first().json).replace(/^\)\]\}\'\n/, '');
let trends;
try {
  trends = JSON.parse(raw);
} catch(e) {
  return [];
}

const trendingSearches = trends?.default?.trendingSearchesDays?.[0]?.trendingSearches || [];

return trendingSearches.slice(0, 20).map(trend => ({
  json: {
    source: 'google_trends',
    title: trend.title?.query || '',
    traffic: trend.formattedTraffic || '',
    articles: trend.articles?.length || 0,
    url: trend.articles?.[0]?.url || '',
    snippet: trend.articles?.[0]?.snippet || '',
    detected_at: new Date().toISOString()
  }
}));
